from flask import Flask

app = Flask(__name__)

@app.route('/')
def home():
    return '<h1>Главная</h1>'

if __name__ == '__main__':
    app.run(debug=True)

@app.route('/')
def home():
    return 'Главная'

@app.route('/about')
def about():
    return 'О нас'

from flask import render_template

@app.route('/user')
def user():
    return render_template('user.html', name='Аня', age=20)

@app.route('/user/<name>')
def profile(name):
    return f'Профиль: {name}'

@app.route('/post/<int:id>')
def post(id):
    return f'Пост № {id}'

from flask import request

@app.route('/search')
def search():
    q = request.args.get('q', '')
    return f'Ищем: {q}'
